mapper.sql:
where a.status not in ('COMPLETED', 'CANCELLED', 'REJECTED') and a.status=#{s.status} and a.priority=#{s.priority}
and ( a.application_no like concat('%',#{s.keyword},'%') or o.order_no like concat('%',#{s.keyword},'%') or o.product_name like concat('%',#{s.keyword},'%') or a.reason_text like concat('%',#{s.keyword},'%') )
and a.sla_deadline < now() and a.sla_deadline between now() and date_add(now(), interval 24 hour) and a.priority in ('HIGH', 'URGENT') and a.status='NEED_MORE_EVIDENCE'
